// loggingUnaryInterceptor logs all unary RPC calls
func loggingUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	log.Printf("Unary RPC: %s", info.FullMethod)
	resp, err := handler(ctx, req)
	if err != nil {
		log.Printf("RPC %s failed: %v", info.FullMethod, err)
	} else {
		log.Printf("RPC %s succeeded", info.FullMethod)
	}
	return resp, err
}

// loggingStreamInterceptor logs all streaming RPC calls
func loggingStreamInterceptor(
	srv interface{},
	ss grpc.ServerStream,
	info *grpc.StreamServerInfo,
	handler grpc.StreamHandler,
) error {
	log.Printf("Stream RPC: %s", info.FullMethod)
	err := handler(srv, ss)
	if err != nil {
		log.Printf("Stream RPC %s failed: %v", info.FullMethod, err)
	} else {
		log.Printf("Stream RPC %s succeeded", info.FullMethod)
	}
	return err
}

